exports.seed = async function (knex) {
  for (const [id, langs] of Object.entries(DATA)) {
    const update = {};
    for (const [lang, fields] of Object.entries(langs)) {
      update[`name_${lang}`] = fields.name;
      update[`significations_${lang}`] = fields.significations;
      update[`keywords_${lang}`] = fields.keywords;
      update[`topics_${lang}`] = fields.topics;
      update[`health_organs_${lang}`] = fields.health_organs;
      update[`detailed_notes_${lang}`] = fields.detailed_notes;
      update[`bhava_nature_${lang}`] = fields.bhava_nature;
    }
    await knex('houses').where({ id: Number(id) }).update(update);
  }
};
